@@ -2387,6 +2387,72 @@
 export { getCS, updateMovement };
+
+// ─── Bubble rendering system ───────────────────────────────────────
+
+/**
+ * Draw a speech bubble above the character.
+ * @param ctx Canvas rendering context
+ * @param x X position (center) above character
+ * @param y Y position (top) above character
+ * @param text Text to display inside bubble
+ */
+export function drawSpeechBubble(ctx: CanvasRenderingContext2D, x: number, y: number, text: string) {
+  ctx.font = '9px monospace';
+  const paddingX = 6;
+  const paddingY = 5;
+  const tailHeight = 6;
+  const tailWidth = 8;
+  const textWidth = ctx.measureText(text).width;
+  const bubbleWidth = textWidth + paddingX * 2;
+  const bubbleHeight = 18;
+  const bx = x - bubbleWidth / 2;
+  const by = y - bubbleHeight - tailHeight;
+
+  // Bubble background
+  ctx.fillStyle = '#f0ead6';
+  ctx.strokeStyle = '#2a2020';
+  ctx.lineWidth = 1.5;
+  roundRect(ctx, bx, by, bubbleWidth, bubbleHeight, 4);
+  ctx.fill();
+  ctx.stroke();
+
+  // Tail (triangle)
+  ctx.beginPath();
+  ctx.moveTo(x - tailWidth / 2, by + bubbleHeight);
+  ctx.lineTo(x, by + bubbleHeight + tailHeight);
+  ctx.lineTo(x + tailWidth / 2, by + bubbleHeight);
+  ctx.closePath();
+  ctx.fillStyle = '#f0ead6';
+  ctx.fill();
+  ctx.stroke();
+
+  // Text
+  ctx.fillStyle = '#1a1020';
+  ctx.fillText(text, bx + paddingX, by + bubbleHeight - 6);
+}
+
+/**
+ * Draw a thought bubble above the character.
+ * @param ctx Canvas rendering context
+ * @param x X position (center) above character
+ * @param y Y position (top) above character
+ * @param text Text to display inside bubble
+ */
+export function drawThoughtBubble(ctx: CanvasRenderingContext2D, x: number, y: number, text: string) {
+  ctx.font = '9px monospace';
+  const paddingX = 6;
+  const paddingY = 5;
+  const tailRadius1 = 4;
+  const tailRadius2 = 2;
+  const textWidth = ctx.measureText(text).width;
+  const bubbleWidth = textWidth + paddingX * 2;
+  const bubbleHeight = 18;
+  const bx = x - bubbleWidth / 2;
+  const by = y - bubbleHeight - tailRadius1 * 2 - 4;
+
+  // Bubble background
+  ctx.fillStyle = '#d8e8f8';
+  ctx.strokeStyle = '#2a2020';
+  ctx.lineWidth = 1.5;
+  roundRect(ctx, bx, by, bubbleWidth, bubbleHeight, 4);
+  ctx.fill();
+  ctx.stroke();
+
+  // Tail (series of circles)
+  ctx.fillStyle = '#d8e8f8';
+  ctx.strokeStyle = '#2a2020';
+  ctx.lineWidth = 1.5;
+  ctx.beginPath();
+  ctx.arc(x - 6, by + bubbleHeight + tailRadius1 + 6, tailRadius2, 0, Math.PI * 2);
+  ctx.fill();
+  ctx.stroke();
+  ctx.beginPath();
+  ctx.arc(x - 2, by + bubbleHeight + tailRadius1 * 2 + 8, tailRadius1, 0, Math.PI * 2);
+  ctx.fill();
+  ctx.stroke();
+
+  // Text
+  ctx.fillStyle = '#1a1020';
+  ctx.fillText(text, bx + paddingX, by + bubbleHeight - 6);
+}
